import React from 'react';
import { useTranslation } from '../hooks/useTranslation';

const SobreMim = () => {
  const { t } = useTranslation();

  return (
    <section id="hero" className="hero">
      <div className="hero-background-image"></div>
      <div className="hero-overlay"></div>
      
      <div className="hero-content-left" data-aos="fade-up">
        <div className="hero-top" data-aos="fade-up" data-aos-delay="100">
          <div className="hero-greeting">Bem-vindo</div>
        </div>
        <div className="hero-info" data-aos="fade-up" data-aos-delay="200">
          <div className="hero-name-wrapper">
            <span className="hero-prefix">Eu sou</span>
            <h1 className="hero-name">Matheus Abib</h1>
          </div>
          <p className="hero-role">Desenvolvedor de software</p>
          <div className="hero-tags" data-aos="fade-up" data-aos-delay="300">
            <span>Front-end</span>
            <span>Back-end</span>
            <span>UI/UX</span>
          </div>
          <p className="hero-description-tagline" data-aos="fade-up" data-aos-delay="400">
            Crio softwares completos, dos requisitos à entrega, unindo tecnologia, design e tomada de decisão.
          </p>
        </div>
      </div>
    </section>
  );
};

export default SobreMim;
